import './style/index.less'
import { useCallback, useEffect, useMemo, useRef, useState } from 'react'
import { useTranslation } from 'react-i18next'
import { useNavigate } from 'react-router-dom'
import { useRequest } from 'ahooks'
import {
  Button,
  DatePicker,
  Form,
  Message,
  Modal,
  Select,
  Space,
} from '@arco-design/web-react'
import type { TableColumnProps } from '@arco-design/web-react'
import {
  IconClose,
  IconEdit,
  IconEye,
  IconPlus,
  IconUpload,
} from '@arco-design/web-react/icon'
import ListFilterHseForm from '@common/components/ListFilterHseForm'
import UnifiedTableStyle from '@common/components/UnifiedTableStyle'
import useDebouncedPromise from '@common/hooks/useDebouncedPromise'
import { getLanguage } from '@common/utils/localStorage'
import { LanguageEnum } from '@common/constants/language'
import { getUserListAll } from '@common/service/apis/user'
import { handelFieldNameShow } from '@/utils/tools'
import { tableHeaderCellStyle } from '@/constants/table'
import {
  MonthlyInspectionStatusEnum,
  STATUS_CODE_TO_KEY,
  STATUS_KEY_TO_CODE,
} from '@/constants/monthlyInspection'
import { monthlyInspectionPage, monthlyInspectionSave } from '@/service/apis'
import type {
  MonthlyInspectionFilterValues,
  MonthlyInspectionRecord,
  MonthlyInspectionStatus,
} from '@/types/MonthlyInspection'
import { renderEllipsisText } from '@common/components/EllipsisText'

const classPrefix = 'monthly-inspection-list'

const MAX_INSPECTORS = 10

const editableStatuses: MonthlyInspectionStatus[] = ['draft']

const MonthlyInspection = () => {
  const { t } = useTranslation(['monthlyInspection', 'common'])
  const navigate = useNavigate()
  const tableRef = useRef<any>(null)
  const [filters, setFilters] = useState<MonthlyInspectionFilterValues>({})
  const [createVisible, setCreateVisible] = useState(false)
  const [createForm] = Form.useForm<{
    inspectionDate?: string
    inspectorIds?: (string | number)[]
  }>()

  const [userList, setUserList] = useState<{ value: number; label: string }[]>(
    [],
  )
  const { run: getUserList } = useRequest(getUserListAll, {
    manual: true,
    onSuccess: (res: any) => {
      if (res) {
        const list = res.map((item: any) => ({
          value: item.userId,
          label: handelFieldNameShow(item.fullName, item.fullNameAr),
        }))
        setUserList(list)
      }
    },
  })

  useEffect(() => {
    if (createVisible) {
      getUserList({})
    }
  }, [createVisible])

  const debouncedMonthlyInspectionSave = useDebouncedPromise(
    monthlyInspectionSave,
    500,
  )
  const { run: runSave, loading: saveLoading } = useRequest(
    debouncedMonthlyInspectionSave,
    {
      manual: true,
      onSuccess: () => {
        Message.success(t('common:message.createSuccessfully'))
        setCreateVisible(false)
        createForm.resetFields()
        tableRef.current?.refresh?.()
      },
    },
  )

  const statusOptions = useMemo(
    () => [
      { label: t('monthlyInspection:status.draft'), value: 'draft' },
      {
        label: t('monthlyInspection:status.underReview'),
        value: 'underReview',
      },
      { label: t('monthlyInspection:status.approved'), value: 'approved' },
      { label: t('monthlyInspection:status.rejected'), value: 'rejected' },
    ],
    [t],
  )

  const getList = useCallback(
    async (params?: { pageNum?: number; pageSize?: number }) => {
      return await monthlyInspectionPage({
        pageNum: params?.pageNum || 1,
        pageSize: params?.pageSize || 10,
        status: filters.status ? STATUS_KEY_TO_CODE[filters.status] : undefined,
        startDate: filters.inspectionDate?.startTime || undefined,
        endDate: filters.inspectionDate?.endTime || undefined,
      })
    },
    [filters],
  )

  const handleSubmit = (values: MonthlyInspectionFilterValues) => {
    setFilters(values || {})
    tableRef.current?.refresh?.()
  }

  const handleReset = () => {
    setFilters({})
    tableRef.current?.refresh?.()
  }

  const handleCreate = () => {
    createForm.resetFields()
    setCreateVisible(true)
  }

  const handleCreateCancel = () => {
    createForm.resetFields()
    setCreateVisible(false)
  }

  const handleCreateConfirm = async () => {
    try {
      const values = await createForm.validate()
      runSave({
        inspectionDate: values.inspectionDate as string,
        inspectorIds: values.inspectorIds as (string | number)[],
      })
    } catch {
      // 表单内联校验已显示错误
    }
  }

  const isLanguageAR = getLanguage() === LanguageEnum.AR

  const handleEditMonthlyInspection = (
    record: MonthlyInspectionRecord,
    editable: boolean,
  ) => {
    const base = editable
      ? '/monthly-inspection/list/inspection-form'
      : '/monthly-inspection/list/inspection-form/view'
    navigate(`${base}/${record.inspectionId}/${record.status}`)
  }

  const columns: TableColumnProps<MonthlyInspectionRecord>[] = [
    {
      title: t('monthlyInspection:columns.inspectionId'),
      dataIndex: 'code',
      headerCellStyle: tableHeaderCellStyle,
      render: (value: string) => value || '-',
    },
    {
      title: t('monthlyInspection:columns.inspectionDate'),
      dataIndex: 'inspectionDate',
      headerCellStyle: tableHeaderCellStyle,
    },
    {
      title: t('monthlyInspection:columns.inspector'),
      dataIndex: 'inspectorList',
      headerCellStyle: tableHeaderCellStyle,
      render: (_v, record) => {
        const data = (record.inspectorList ?? [])
          .map((item) =>
            isLanguageAR ? item.inspectorNameAr : item.inspectorName,
          )
          .filter(Boolean)
          .join(', ')
        return renderEllipsisText(data)
      },
    },
    {
      title: t('monthlyInspection:columns.issuesObserved'),
      dataIndex: 'issuesObserved',
      headerCellStyle: tableHeaderCellStyle,
      render: (value: number | null) => (value === null ? '-' : value),
    },
    {
      title: t('monthlyInspection:columns.status'),
      dataIndex: 'status',
      headerCellStyle: tableHeaderCellStyle,
      render: (value: MonthlyInspectionStatusEnum) => {
        const key = STATUS_CODE_TO_KEY[value]
        return (
          <span
            className={`${classPrefix}__status ${classPrefix}__status--${key}`}
          >
            <span className={`${classPrefix}__status-dot`} />
            <span>{t(`monthlyInspection:status.${key}`)}</span>
          </span>
        )
      },
    },
    {
      title: t('monthlyInspection:columns.action'),
      dataIndex: 'action',
      width: 100,
      fixed: 'right',
      headerCellStyle: tableHeaderCellStyle,
      render: (_value, record) => {
        const key = STATUS_CODE_TO_KEY[record.status]
        const editable = editableStatuses.includes(key)
        return (
          <Button
            type='text'
            size='mini'
            className={`${classPrefix}__action-btn`}
            onClick={() => handleEditMonthlyInspection(record, editable)}
            style={{ fontSize: '14px' }}
          >
            <Space size={4}>
              {editable ? <IconEdit /> : <IconEye />}
              <span>
                {t(
                  editable
                    ? 'monthlyInspection:actions.edit'
                    : 'monthlyInspection:actions.view',
                )}
              </span>
            </Space>
          </Button>
        )
      },
    },
  ]

  return (
    <div className={`${classPrefix}`}>
      <div className={`${classPrefix}-header`}>
        <div className={`${classPrefix}-title`}>
          {t('monthlyInspection:title')}
        </div>
        <ListFilterHseForm
          showKeywordInput={false}
          onSubmit={handleSubmit}
          onReset={handleReset}
          renderBtnJsx={
            <Button type='primary' icon={<IconPlus />} onClick={handleCreate}>
              {t('monthlyInspection:addButton')}
            </Button>
          }
        >
          <div className='search-form-box'>
            <Form.Item field='status'>
              <Select
                allowClear
                placeholder={t('monthlyInspection:filters.status')}
                options={statusOptions}
                style={{ width: 180 }}
              />
            </Form.Item>
            <Form.Item
              field='inspectionDate'
              normalize={(value) => ({
                startTime: value && value[0],
                endTime: value && value[1],
              })}
              formatter={(value) =>
                value && value.startTime ? [value.startTime, value.endTime] : []
              }
            >
              <DatePicker.RangePicker
                dayStartOfWeek={0}
                format='DD/MM//YYYY'
                placeholder={[
                  t('monthlyInspection:filters.dateRangeStart'),
                  t('monthlyInspection:filters.dateRangeEnd'),
                ]}
                style={{ width: 240 }}
              />
            </Form.Item>
          </div>
        </ListFilterHseForm>
      </div>
      <div className={`${classPrefix}-table`}>
        <UnifiedTableStyle
          ref={tableRef}
          rowKey='inspectionId'
          columns={columns}
          getList={getList}
          showNoColumn={false}
          loading={true}
          showPagination={true}
          border={true}
        />
      </div>
      <Modal
        title={t('monthlyInspection:createModal.title')}
        visible={createVisible}
        onCancel={handleCreateCancel}
        maskClosable={false}
        unmountOnExit
        className={`${classPrefix}__create-modal`}
        footer={
          <Space size={12}>
            <Button icon={<IconClose />} onClick={handleCreateCancel}>
              {t('common:btn.cancel')}
            </Button>
            <Button
              type='primary'
              icon={<IconUpload />}
              loading={saveLoading}
              onClick={handleCreateConfirm}
            >
              {t('common:btn.create')}
            </Button>
          </Space>
        }
      >
        <Form form={createForm} layout='vertical'>
          <Form.Item
            label={t('monthlyInspection:columns.inspectionDate')}
            field='inspectionDate'
            rules={[{ required: true }]}
          >
            <DatePicker
              style={{ width: '100%' }}
              format='DD/MM/YYYY'
              placeholder={t('monthlyInspection:createModal.datePlaceholder')}
            />
          </Form.Item>
          <Form.Item
            label={t('monthlyInspection:columns.inspector')}
            field='inspectorIds'
            rules={[
              {
                required: true,
                type: 'array',
                minLength: 1,
                message: t('common:pleaseSelect'),
              },
              {
                validator: (value, cb) => {
                  if (Array.isArray(value) && value.length > MAX_INSPECTORS) {
                    cb(
                      t('monthlyInspection:messages.inspectorMaxLimit', {
                        max: MAX_INSPECTORS,
                      }),
                    )
                  } else {
                    cb()
                  }
                },
              },
            ]}
          >
            <Select
              allowClear
              showSearch
              mode='multiple'
              maxTagCount='responsive'
              options={userList}
              filterOption={(inputValue, option) =>
                String(option?.props?.children ?? '')
                  .toLowerCase()
                  .indexOf(inputValue.toLowerCase()) >= 0
              }
              placeholder={t('common:pleaseSelect')}
            />
          </Form.Item>
        </Form>
      </Modal>
    </div>
  )
}

export default MonthlyInspection

import './style/index.less'
import { useEffect, useRef, useState } from 'react'
import { useTranslation } from 'react-i18next'
import { useRequest } from 'ahooks'
import {
  Button,
  Input,
  Message,
  Modal,
  Spin,
  Switch,
  TreeSelect,
  Link
} from '@arco-design/web-react'
import useDebouncedPromise from '@common/hooks/useDebouncedPromise'
import { handelFieldNameShow, orgTransformData } from '@/utils/tools'
import type { TransformedOrgNode } from '@/utils/tools'
import { PatrolFormSetupTypeEnum } from '@/constants/PatrolFormSetup'
import { getOrgTreeRecursion, patrolPage, patrolSave } from '@/service/apis'
import type {
  PatrolSavePayload,
  PatrolSectionResp,
} from '@/service/apis/patrolSection'

import LangPrefixAr from '@/assets/images/icon/lang-prefix-ar-icon.svg?react'
import LangPrefixEn from '@/assets/images/icon/lang-prefix-en-icon.svg?react'

import {
  IconClose,
  IconCloseCircleFill,
  IconDelete,
  IconDragDot,
  IconEdit,
  IconInfoCircle,
  IconPlus,
  IconUpload,
} from '@arco-design/web-react/icon'
import { v4 as uuidv4 } from 'uuid'
import _ from 'lodash'

const classPrefix = 'patrol-form-setup'

type TabKey = 'around' | 'inside' | 'parking'

interface CheckItem {
  id: string
  itemId?: number
  textAr: string
  textEn: string
  orgId?: string
}

interface Section {
  id: string
  sectionId?: number
  titleAr: string
  titleEn: string
  items: CheckItem[]
}

type TabData = Record<TabKey, Section[]>

const findOrgTitleByKey = (
  nodes: TransformedOrgNode[] | undefined,
  key: number | string | undefined,
): string => {
  if (!nodes || key == null) return ''
  for (const node of nodes) {
    if (String(node.key) === String(key)) return node.title
    if (node.children) {
      const hit = findOrgTitleByKey(node.children, key)
      if (hit) return hit
    }
  }
  return ''
}

const TABS: { key: TabKey; labelKey: string }[] = [
  { key: 'around', labelKey: 'securityPatrol:formSetup.tabs.around' },
  { key: 'inside', labelKey: 'securityPatrol:formSetup.tabs.inside' },
  { key: 'parking', labelKey: 'securityPatrol:formSetup.tabs.parking' },
]

const TAB_KEY_TO_TYPE: Record<TabKey, PatrolFormSetupTypeEnum> = {
  around: PatrolFormSetupTypeEnum.Around,
  inside: PatrolFormSetupTypeEnum.Inside,
  parking: PatrolFormSetupTypeEnum.Parking,
}

const emptyTabData: TabData = {
  around: [],
  inside: [],
  parking: [],
}

const mapApiToSections = (resp: PatrolSectionResp[]): Section[] =>
  (resp || []).map((s) => ({
    id: uuidv4(),
    sectionId: s.sectionId,
    titleEn: s.name,
    titleAr: s.nameAr,
    items: (s.items || []).map((it) => ({
      id: uuidv4(),
      itemId: it.itemId,
      textEn: it.name,
      textAr: it.nameAr,
      orgId: it.orgId != null ? String(it.orgId) : undefined,
    })),
  }))

// ─── Main component ──────────────────────────────────────────────────────────
const PatrolFormSetup = () => {
  const { t } = useTranslation(['securityPatrol', 'common'])

  const [activeTab, setActiveTab] = useState<TabKey>('around')
  const [isEditing, setIsEditing] = useState(false)
  const [savedData, setSavedData] = useState<TabData>(emptyTabData)
  const [draftData, setDraftData] = useState<TabData>(emptyTabData)
  const [fillInEnglish, setFillInEnglish] = useState(false)
  const [orgData, setOrgData] = useState<TransformedOrgNode[]>()
  const [sectionsLoading, setSectionsLoading] = useState(true)

  const { run: fetchSections } = useRequest(patrolPage, {
    manual: true,
    onSuccess: (res, params) => {
      const tabKey = (Object.keys(TAB_KEY_TO_TYPE) as TabKey[]).find(
        (key) => TAB_KEY_TO_TYPE[key] === params[0].type,
      )
      if (!tabKey) return
      const sections = mapApiToSections(res || [])
      setSavedData((prev) => ({ ...prev, [tabKey]: sections }))
      setDraftData((prev) => ({ ...prev, [tabKey]: sections }))
    },
    onFinally: () => {
      setSectionsLoading(false)
      setIsEditing(false)
    },
  })

  const { run: fetchOrgTree } = useRequest(getOrgTreeRecursion, {
    manual: true,
    onSuccess: (res: any) => {
      setOrgData(orgTransformData(res || []))
    },
  })

  useEffect(() => {
    fetchOrgTree()
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [])

  useEffect(() => {
    setSectionsLoading(true)
    fetchSections({ type: TAB_KEY_TO_TYPE[activeTab] })
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [activeTab])

  const debouncedPatrolSave = useDebouncedPromise(patrolSave, 500)
  const { run: runSave, loading: saveLoading } = useRequest(
    debouncedPatrolSave,
    {
      manual: true,
      onSuccess: () => {
        Message.success(t('common:message.saveSuccessfully'))

        fetchSections({ type: TAB_KEY_TO_TYPE[activeTab] })
      },
    },
  )

  // ── Drag state (section) ───────────────────────────────────────────────
  const dragSectionIdx = useRef<number | null>(null)
  const dragOverSectionIdx = useRef<number | null>(null)
  const [, forceUpdate] = useState(0)
  const rerender = () => forceUpdate((n) => n + 1)

  // ── Drag state (item) ──────────────────────────────────────────────────
  const dragItemInfo = useRef<{ sectionIdx: number; itemIdx: number } | null>(
    null,
  )
  const dragOverItemInfo = useRef<{
    sectionIdx: number
    itemIdx: number
  } | null>(null)

  // ── Draft helpers ──────────────────────────────────────────────────────
  const currentSections = isEditing
    ? draftData[activeTab]
    : savedData[activeTab]

  const updateDraft = (updater: (prev: TabData) => TabData) => {
    setDraftData((prev) => updater(prev))
  }

  const updateTabSections = (sections: Section[]) => {
    updateDraft((prev) => ({ ...prev, [activeTab]: sections }))
  }

  // ── Edit actions ───────────────────────────────────────────────────────
  const handleEdit = () => {
    setDraftData(savedData)
    setIsEditing(true)
  }

  const handleCancel = () => {
    setIsEditing(false)
  }

  const isCurrentTabDirty =
    isEditing && !_.isEqual(draftData[activeTab], savedData[activeTab])

  const handleTabClick = (next: TabKey) => {
    if (next === activeTab) return
    if (isCurrentTabDirty) {
      Modal.confirm({
        title: t('common:confirmation'),
        content: t('securityPatrol:formSetup.unsavedChangesConfirm'),
        okText: t('common:btn.confirm'),
        cancelText: t('common:btn.cancel'),
        onOk: () => {
          setDraftData(savedData)
          setActiveTab(next)
        },
      })
      return
    }
    setActiveTab(next)
  }

  const hasEmptyTextAr = (data: CheckItem[]) => {
    return data.some((subItem) => subItem.textAr === '')
  }
  const handleConfirm = () => {
    const sections = draftData[activeTab]
    for (const sec of sections) {
      if (hasEmptyTextAr(sec.items)) {
        Message.warning(
          t('securityPatrol:formSetup.pleaseCompleteRequiredFields'),
        )
        return
      }
    }

    const payload: PatrolSavePayload = {
      type: TAB_KEY_TO_TYPE[activeTab],
      sections: sections.map((sec, secIdx) => ({
        sectionId: sec.sectionId,
        name: sec.titleEn,
        nameAr: sec.titleAr,
        sort: secIdx,
        items: sec.items.map((it, idx) => ({
          itemId: it.itemId,
          name: it.textEn,
          nameAr: it.textAr,
          orgId: it.orgId,
          sort: idx,
        })),
      })),
    }

    runSave(payload)
  }

  // ── Section actions ────────────────────────────────────────────────────
  const handleAddSection = () => {
    const newSection: Section = {
      id: uuidv4(),
      titleAr: '',
      titleEn: '',
      items: [{ id: uuidv4(), textAr: '', textEn: '', orgId: undefined }],
    }
    updateTabSections([...currentSections, newSection])
  }

  const handleDeleteSection = (sectionIdx: number) => {
    updateTabSections(currentSections.filter((_, i) => i !== sectionIdx))
  }

  const handleSectionTitleChange = (sectionIdx: number, value: string) => {
    const updated = currentSections.map((sec, i) => {
      if (i !== sectionIdx) return sec
      return fillInEnglish
        ? { ...sec, titleEn: value }
        : { ...sec, titleAr: value }
    })
    updateTabSections(updated)
  }

  const handleItemOrgChange = (
    sectionIdx: number,
    itemIdx: number,
    value: string | undefined,
  ) => {
    const updated = currentSections.map((sec, i) => {
      if (i !== sectionIdx) return sec
      return {
        ...sec,
        items: sec.items.map((item, j) =>
          j === itemIdx ? { ...item, orgId: value } : item,
        ),
      }
    })
    updateTabSections(updated)
  }

  // ── Item actions ───────────────────────────────────────────────────────
  const handleAddItem = (sectionIdx: number) => {
    const updated = currentSections.map((sec, i) => {
      if (i !== sectionIdx) return sec
      return {
        ...sec,
        items: [...sec.items, { id: uuidv4(), textAr: '', textEn: '' }],
      }
    })
    updateTabSections(updated)
  }

  const handleDeleteItem = (sectionIdx: number, itemIdx: number) => {
    const updated = currentSections.map((sec, i) => {
      if (i !== sectionIdx) return sec
      return { ...sec, items: sec.items.filter((_, j) => j !== itemIdx) }
    })
    updateTabSections(updated)
  }

  const handleItemTextChange = (
    sectionIdx: number,
    itemIdx: number,
    value: string,
  ) => {
    const updated = currentSections.map((sec, i) => {
      if (i !== sectionIdx) return sec
      return {
        ...sec,
        items: sec.items.map((item, j) => {
          if (j !== itemIdx) return item
          return fillInEnglish
            ? { ...item, textEn: value }
            : { ...item, textAr: value }
        }),
      }
    })
    updateTabSections(updated)
  }

  // ── Section drag ───────────────────────────────────────────────────────
  const handleSectionDragStart = (idx: number) => {
    dragSectionIdx.current = idx
  }

  const handleSectionDragOver = (e: React.DragEvent, idx: number) => {
    e.preventDefault()
    dragOverSectionIdx.current = idx
    rerender()
  }

  const handleSectionDrop = () => {
    const from = dragSectionIdx.current
    const to = dragOverSectionIdx.current
    if (from !== null && to !== null && from !== to) {
      const next = [...currentSections]
      const [moved] = next.splice(from, 1)
      next.splice(to, 0, moved)
      updateTabSections(next)
    }
    dragSectionIdx.current = null
    dragOverSectionIdx.current = null
    rerender()
  }

  const handleSectionDragEnd = () => {
    dragSectionIdx.current = null
    dragOverSectionIdx.current = null
    rerender()
  }

  // ── Item drag ──────────────────────────────────────────────────────────
  const handleItemDragStart = (sectionIdx: number, itemIdx: number) => {
    dragItemInfo.current = { sectionIdx, itemIdx }
  }

  const handleItemDragOver = (
    e: React.DragEvent,
    sectionIdx: number,
    itemIdx: number,
  ) => {
    e.preventDefault()
    e.stopPropagation()
    dragOverItemInfo.current = { sectionIdx, itemIdx }
    rerender()
  }

  const handleItemDrop = (e: React.DragEvent, targetSectionIdx: number) => {
    e.stopPropagation()
    const from = dragItemInfo.current
    const to = dragOverItemInfo.current
    if (
      from &&
      to &&
      from.sectionIdx === targetSectionIdx &&
      from.sectionIdx === to.sectionIdx &&
      from.itemIdx !== to.itemIdx
    ) {
      const updated = currentSections.map((sec, i) => {
        if (i !== from.sectionIdx) return sec
        const next = [...sec.items]
        const [moved] = next.splice(from.itemIdx, 1)
        next.splice(to.itemIdx, 0, moved)
        return { ...sec, items: next }
      })
      updateTabSections(updated)
    }
    dragItemInfo.current = null
    dragOverItemInfo.current = null
    rerender()
  }

  const handleItemDragEnd = () => {
    dragItemInfo.current = null
    dragOverItemInfo.current = null
    rerender()
  }

  // ── Render ─────────────────────────────────────────────────────────────
  return (
    <div className={`${classPrefix}`}>
      {/* ── Top bar ── */}
      <div className={`${classPrefix}__topbar`}>
        <div className={`${classPrefix}__title`}>
          {t('securityPatrol:formSetup.title')}
        </div>

        <div className={`${classPrefix}__topbar-right`}>
          {/* Tabs */}
          <div className={`${classPrefix}__tabs`}>
            {TABS.map((tab) => (
              <button
                key={tab.key}
                className={`${classPrefix}__tab${activeTab === tab.key ? ` ${classPrefix}__tab--active` : ''}`}
                onClick={() => handleTabClick(tab.key)}
              >
                {t(tab.labelKey)}
              </button>
            ))}
          </div>

          {/* Action buttons */}
          {isEditing ? (
            <div className={`${classPrefix}__action-btns`}>
              <Button icon={<IconClose />} onClick={handleCancel}>
                {t('common:btn.cancel')}
              </Button>
              <Button
                type='primary'
                icon={<IconUpload />}
                loading={saveLoading}
                className={`${classPrefix}__confirm-btn`}
                onClick={handleConfirm}
              >
                {t('common:btn.confirm')}
              </Button>
            </div>
          ) : (
            <div className={`${classPrefix}__action-btns`}>
              <Button
                type='primary'
                icon={<IconEdit />}
                className={`${classPrefix}__confirm-btn`}
                onClick={handleEdit}
              >
                {t('common:btn.edit')}
              </Button>
            </div>
          )}
        </div>
      </div>

      {/* <div className={`${classPrefix}__divider`} /> */}

      {/* ── Edit toolbar ── */}
      {isEditing && (
        <div className={`${classPrefix}__edit-toolbar`}>
          <Button type='outline' icon={<IconPlus />} onClick={handleAddSection}>
            {t('securityPatrol:formSetup.addSection')}
          </Button>
          <div className={`${classPrefix}__fill-en`}>
            <span className={`${classPrefix}__fill-en-label`}>
              {t('securityPatrol:formSetup.fillInEnglish')}
            </span>
            <Switch
              checked={fillInEnglish}
              onChange={(v) => setFillInEnglish(v)}
              size='small'
            />
          </div>
        </div>
      )}

      {/* ── Floors apply hint (inside / parking) ── */}
      {(activeTab === 'inside' || activeTab === 'parking') && (
        <div className={`${classPrefix}__floors-hint`}>
          <IconInfoCircle className={`${classPrefix}__floors-hint-icon`} />
          <span>
            {activeTab === 'parking'
              ? t('securityPatrol:formSetup.parkingFloorsApplyHint')
              : t('securityPatrol:formSetup.floorsApplyHint')}
          </span>
        </div>
      )}

      {/* ── Content ── */}
      <Spin loading={sectionsLoading} block className={`${classPrefix}__spin`}>
        {!sectionsLoading &&
          (currentSections.length > 0 ? (
            currentSections.map((section, sectionIdx) => {
              const isDragOverSection =
                isEditing && dragOverSectionIdx.current === sectionIdx

              return (
                <div
                  key={section.id}
                  className={`${classPrefix}__section${isDragOverSection ? ` ${classPrefix}__section--drag-over` : ''}`}
                  draggable={isEditing}
                  onDragStart={() => handleSectionDragStart(sectionIdx)}
                  onDragOver={(e) => handleSectionDragOver(e, sectionIdx)}
                  onDrop={handleSectionDrop}
                  onDragEnd={handleSectionDragEnd}
                >
                  {/* Section header */}
                  <div className={`${classPrefix}__section-header`}>
                    {isEditing && (
                      <span
                        className={`${classPrefix}__drag-handle ${classPrefix}__drag-handle--section`}
                      >
                        <IconDragDot style={{ color: '#4E5969' }} />
                      </span>
                    )}

                    <span className={`${classPrefix}__section-badge`}>
                      {t('securityPatrol:formSetup.sectionLabel', {
                        n: sectionIdx + 1,
                      })}
                    </span>

                    {isEditing ? (
                      <>
                        <Input
                          className={`${classPrefix}__section-title-input ${fillInEnglish ? '' : 'rtl-input'}`}
                          prefix={
                            fillInEnglish ? (
                              <LangPrefixEn
                                style={{ width: '28px', height: '20px' }}
                              />
                            ) : (
                              <LangPrefixAr
                                style={{ width: '28px', height: '20px' }}
                              />
                            )
                          }
                          value={
                            fillInEnglish ? section.titleEn : section.titleAr
                          }
                          placeholder={t(
                            'securityPatrol:formSetup.sectionTitlePlaceholder',
                          )}
                          onChange={(v) =>
                            handleSectionTitleChange(sectionIdx, v)
                          }
                          onClick={(e) => e.stopPropagation()}
                          onDragStart={(e) => e.stopPropagation()}
                        />
                        <Button
                          type='outline'
                          size='mini'
                          icon={<IconDelete />}
                          className={`${classPrefix}__delete-btn`}
                          onClick={(e) => {
                            e.stopPropagation()
                            handleDeleteSection(sectionIdx)
                          }}
                        >
                          {t('common:btn.delete')}
                        </Button>
                      </>
                    ) : (
                      <span className={`${classPrefix}__section-title`}>
                        {handelFieldNameShow(section.titleEn, section.titleAr)}
                      </span>
                    )}
                  </div>

                  {/* Items */}
                  {section.items.map((item, itemIdx) => {
                    const isItemDragOver =
                      isEditing &&
                      dragOverItemInfo.current?.sectionIdx === sectionIdx &&
                      dragOverItemInfo.current?.itemIdx === itemIdx

                    return (
                      <div
                        key={item.id}
                        className={`${classPrefix}__item${isItemDragOver ? ` ${classPrefix}__item--drag-over` : ''}`}
                        draggable={isEditing}
                        onDragStart={(e) => {
                          if (!isEditing) return
                          e.stopPropagation()
                          handleItemDragStart(sectionIdx, itemIdx)
                        }}
                        onDragOver={(e) => {
                          if (!isEditing) return
                          handleItemDragOver(e, sectionIdx, itemIdx)
                        }}
                        onDrop={(e) => {
                          if (!isEditing) return
                          handleItemDrop(e, sectionIdx)
                        }}
                        onDragEnd={() => {
                          if (!isEditing) return
                          handleItemDragEnd()
                        }}
                      >
                        {isEditing ? (
                          <div className='edit-table-item'>
                            <span className={`${classPrefix}__drag-handle`}>
                              <IconDragDot style={{ color: '#4E5969' }} />
                            </span>
                            <Input
                              className={`${classPrefix}__item-input  ${fillInEnglish ? '' : 'rtl-input'} `}
                              prefix={
                                fillInEnglish ? (
                                  <LangPrefixEn
                                    style={{ width: '28px', height: '20px' }}
                                  />
                                ) : (
                                  <LangPrefixAr
                                    style={{ width: '28px', height: '20px' }}
                                  />
                                )
                              }
                              value={fillInEnglish ? item.textEn : item.textAr}
                              placeholder={t(
                                'securityPatrol:formSetup.itemPlaceholder',
                              )}
                              onChange={(v) =>
                                handleItemTextChange(sectionIdx, itemIdx, v)
                              }
                              onClick={(e) => e.stopPropagation()}
                              onDragStart={(e) => e.stopPropagation()}
                            />
                            <span className={`${classPrefix}__item-dept-label`}>
                              {t('securityPatrol:formSetup.responsibleDept')}:
                            </span>
                            <TreeSelect
                              className={`${classPrefix}__item-dept-select`}
                              value={item.orgId ?? undefined}
                              treeData={orgData}
                              placeholder={t('common:pleaseSelect')}
                              allowClear
                              onChange={(v: string | undefined) =>
                                handleItemOrgChange(
                                  sectionIdx,
                                  itemIdx,
                                  v != null && v !== '' ? v : undefined,
                                )
                              }
                              onClick={(e: React.MouseEvent) =>
                                e.stopPropagation()
                              }
                            />
                            <Link
                              type='text'
                              icon={
                                <IconCloseCircleFill
                                  style={{ width: '23px', height: '23px' }}
                                />
                              }
                              className={`${classPrefix}__item-remove`}
                              onClick={(e) => {
                                e.stopPropagation()
                                handleDeleteItem(sectionIdx, itemIdx)
                              }}
                            />
                          </div>
                        ) : (
                          <div className='table-item'>
                            <span className={`${classPrefix}__item-text`}>
                              {handelFieldNameShow(item.textEn, item.textAr)}
                            </span>
                            <div className={`${classPrefix}__item-dept`}>
                              <span
                                className={`${classPrefix}__item-dept-label`}
                              >
                                {t('securityPatrol:formSetup.responsibleDept')}:
                              </span>
                              <span
                                className={`${classPrefix}__item-dept-value`}
                              >
                                {findOrgTitleByKey(orgData, item.orgId)}
                              </span>
                            </div>
                          </div>
                        )}
                      </div>
                    )
                  })}

                  {/* Add item row */}
                  {isEditing && (
                    <div className={`${classPrefix}__add-item`}>
                      <Button
                        type='text'
                        size='mini'
                        icon={<IconPlus />}
                        className={`${classPrefix}__add-item-btn`}
                        onClick={(e) => {
                          e.stopPropagation()
                          handleAddItem(sectionIdx)
                        }}
                      >
                        {t('securityPatrol:formSetup.addItem')}
                      </Button>
                    </div>
                  )}
                </div>
              )
            })
          ) : (
            <div className={`${classPrefix}__content`}>
              <div className={`${classPrefix}__empty`}>
                <div className={`${classPrefix}__empty-text`}>
                  {t('securityPatrol:formSetup.noSections')}
                </div>
                <Button
                  type='primary'
                  icon={<IconPlus />}
                  className={`${classPrefix}__empty-add-btn`}
                  onClick={() => {
                    if (!isEditing) handleEdit()
                    handleAddSection()
                  }}
                >
                  {t('securityPatrol:formSetup.addSection')}
                </Button>
              </div>
            </div>
          ))}
      </Spin>
    </div>
  )
}

export default PatrolFormSetup

