.monthly-inspection-list {
  box-sizing: border-box;
  margin-top: 16px;
  overflow: hidden;
  width: 100%;
  background-color: #fff;
  border-radius: 12px;
  box-shadow: 0px 4px 8px rgba(0, 0, 0, 0.05);
  padding: 16px;

  &-header {
    padding: 16px;
    border-radius: 10px;
    box-shadow:
      0 9px 11.5px 0 rgba(0, 0, 0, 0.04),
      0 0 12.6px 0 rgba(0, 0, 0, 0.07);
    margin-bottom: 24px;
  }
  &-title {
    color: #000;
    font-size: 24px;
    font-weight: 500;
    text-transform: uppercase;
  }
  .search-form-box {
    display: flex;
    flex-direction: row;
  }

  &__status {
    display: inline-flex;
    align-items: center;
    gap: 6px;

    &-dot {
      display: inline-block;
      width: 8px;
      height: 8px;
      border-radius: 50%;
      background-color: #86909c;
    }
    &--draft &-dot {
      background-color: #86909c;
    }
    &--underReview &-dot {
      background-color: #ff7d00;
    }
    &--approved &-dot {
      background-color: #45ad5e;
    }
    &--rejected &-dot {
      background-color: #f5626c;
    }
  }

  &__action-btn {
    color: #196d65;
    margin-inline-start: -12px;
  }
}

.monthly-inspection-list__create-modal {
  .arco-modal-footer {
    text-align: right;
  }
}

