    width: 100%;
    border-radius: 8px;
    border: 1px solid #e5e6eb;
    overflow: hidden;
  }

  &__status {
    display: inline-flex;
    align-items: center;
    gap: 6px;

    &-dot {
      display: inline-block;
      width: 8px;
      height: 8px;
      border-radius: 50%;
      background-color: #86909c;
    }
    &--draft &-dot {
      background-color: #86909c;
    }
    &--underReview &-dot {
      background-color: #ff7d00;
    }
    &--approved &-dot {
      background-color: #45ad5e;
    }
    &--rejected &-dot {
      background-color: #f5626c;
    }
  }

  &__action-btn {
    color: #196d65;
    margin-inline-start: -12px;
  }
}

.monthly-inspection-list__create-modal {
  .arco-modal-footer {
    text-align: right;
  }
}

