.monthly-inspection-list {
  box-sizing: border-box;
  margin-top: 16px;
  width: 100%;
  background-color: #fff;
  border-radius: 12px;
  box-shadow: 0px 4px 8px rgba(0, 0, 0, 0.05);
  padding: 24px;
  height: calc(100vh - 80px);

  &-header {
    display: flex;
    flex-direction: column;
    gap: 16px;
    padding: 16px;
    border-radius: 10px;
    border: 1px solid rgb(240, 240, 240);
    box-shadow:
      0px 9px 11.5px 0px rgba(0, 0, 0, 0.04),
      0px 0px 12.6px 0px rgba(0, 0, 0, 0.07);
