import './style/index.less'
import { useEffect, useRef, useState } from 'react'
import { useTranslation } from 'react-i18next'
import { useRequest } from 'ahooks'
import {
  Button,
  Input,
  Message,
  Modal,
  Spin,
  Switch,
  TreeSelect,
} from '@arco-design/web-react'
import useDebouncedPromise from '@common/hooks/useDebouncedPromise'
import { handelFieldNameShow, orgTransformData } from '@/utils/tools'
import type { TransformedOrgNode } from '@/utils/tools'
import { InspectionFormSetupTypeEnum } from '@/constants/InspectionFormSetup'
import {
  getOrgTreeRecursion,
  inspectionPage,
  inspectionSave,
} from '@/service/apis'
import type {
  InspectionSavePayload,
  InspectionSectionResp,
} from '@/service/apis/inspectionSection'

import LangPrefixAr from '@/assets/images/icon/lang-prefix-ar-icon.svg?react'
import LangPrefixEn from '@/assets/images/icon/lang-prefix-en-icon.svg?react'

import {
  IconClose,
  IconCloseCircleFill,
  IconDelete,
  IconDragDot,
  IconEdit,
  IconInfoCircle,
  IconPlus,
  IconUpload,
} from '@arco-design/web-react/icon'
import { v4 as uuidv4 } from 'uuid'
import _ from 'lodash'

const classPrefix = 'inspection-form-setup'

type TabKey = 'around' | 'inside' | 'parking'

interface CheckItem {
  id: string
  itemId?: number
  textAr: string
  textEn: string
  // 雪花 ID,必须保持 string(Number() 会丢精度,导致 TreeSelect 匹配不到节点、保存的 id 错误)
  orgId?: string
}

interface Section {
  id: string
  sectionId?: number
  titleAr: string
  titleEn: string
  items: CheckItem[]
}

type TabData = Record<TabKey, Section[]>

const findOrgTitleByKey = (
  nodes: TransformedOrgNode[] | undefined,
  key: number | string | undefined,
): string => {
  if (!nodes || key == null) return ''
  for (const node of nodes) {
    if (String(node.key) === String(key)) return node.title
    if (node.children) {
      const hit = findOrgTitleByKey(node.children, key)
      if (hit) return hit
    }
  }
  return ''
}

const TABS: { key: TabKey; labelKey: string }[] = [
  { key: 'around', labelKey: 'monthlyInspection:form.tabs.around' },
  { key: 'inside', labelKey: 'monthlyInspection:form.tabs.inside' },
  { key: 'parking', labelKey: 'monthlyInspection:form.tabs.parking' },
]

const TAB_KEY_TO_TYPE: Record<TabKey, InspectionFormSetupTypeEnum> = {
  around: InspectionFormSetupTypeEnum.Around,
  inside: InspectionFormSetupTypeEnum.Inside,
  parking: InspectionFormSetupTypeEnum.Parking,
}

const emptyTabData: TabData = {
  around: [],
  inside: [],
  parking: [],
}

const mapApiToSections = (resp: InspectionSectionResp[]): Section[] =>
  (resp || []).map((s) => ({
    id: uuidv4(),
    sectionId: s.sectionId,
    titleEn: s.name,
    titleAr: s.nameAr,
    items: (s.items || []).map((it) => ({
      id: uuidv4(),
      itemId: it.itemId,
      textEn: it.name,
      textAr: it.nameAr,
      // 防御性转换:即使后端返回数字也统一成 string
      orgId: it.orgId != null ? String(it.orgId) : undefined,
    })),
  }))

// ─── Main component ──────────────────────────────────────────────────────────
const InspectionFormSetup = () => {
  const { t } = useTranslation(['monthlyInspection', 'common'])

  const [activeTab, setActiveTab] = useState<TabKey>('around')
  const [isEditing, setIsEditing] = useState(false)
  const [savedData, setSavedData] = useState<TabData>(emptyTabData)
  const [draftData, setDraftData] = useState<TabData>(emptyTabData)
  const [fillInEnglish, setFillInEnglish] = useState(false)
  const [orgData, setOrgData] = useState<TransformedOrgNode[]>()
  const [sectionsLoading, setSectionsLoading] = useState(true)

  const { run: fetchSections } = useRequest(inspectionPage, {
    manual: true,
    onSuccess: (res, params) => {
      const tabKey = (Object.keys(TAB_KEY_TO_TYPE) as TabKey[]).find(
        (key) => TAB_KEY_TO_TYPE[key] === params[0].type,
      )
      if (!tabKey) return
      const sections = mapApiToSections(res || [])
      setSavedData((prev) => ({ ...prev, [tabKey]: sections }))
      setDraftData((prev) => ({ ...prev, [tabKey]: sections }))
    },
    onFinally: () => {
      setSectionsLoading(false)
      setIsEditing(false)
    },
  })

  const { run: fetchOrgTree } = useRequest(getOrgTreeRecursion, {
    manual: true,
    onSuccess: (res: any) => {
      setOrgData(orgTransformData(res || []))
    },
  })

  useEffect(() => {
    fetchOrgTree()
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [])

  useEffect(() => {
    setSectionsLoading(true)
    fetchSections({ type: TAB_KEY_TO_TYPE[activeTab] })
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [activeTab])

  const debouncedInspectionSave = useDebouncedPromise(inspectionSave, 500)
  const { run: runSave, loading: saveLoading } = useRequest(
    debouncedInspectionSave,
    {
      manual: true,
      onSuccess: () => {
        Message.success(t('common:message.saveSuccessfully'))
        fetchSections({ type: TAB_KEY_TO_TYPE[activeTab] })
      },
    },
  )

  // ── Drag state (section) ───────────────────────────────────────────────
  const dragSectionIdx = useRef<number | null>(null)
  const dragOverSectionIdx = useRef<number | null>(null)
  const [, forceUpdate] = useState(0)
  const rerender = () => forceUpdate((n) => n + 1)

  // ── Drag state (item) ──────────────────────────────────────────────────
  const dragItemInfo = useRef<{ sectionIdx: number; itemIdx: number } | null>(
    null,
  )
  const dragOverItemInfo = useRef<{
    sectionIdx: number
    itemIdx: number
  } | null>(null)

  // ── Draft helpers ──────────────────────────────────────────────────────
  const currentSections = isEditing
    ? draftData[activeTab]
    : savedData[activeTab]

  const updateDraft = (updater: (prev: TabData) => TabData) => {
    setDraftData((prev) => updater(prev))
  }

  const updateTabSections = (sections: Section[]) => {
    updateDraft((prev) => ({ ...prev, [activeTab]: sections }))
  }

  // ── Edit actions ───────────────────────────────────────────────────────
  const handleEdit = () => {
    setDraftData(savedData)
    setIsEditing(true)
  }

  const handleCancel = () => {
    setIsEditing(false)
  }

  const isCurrentTabDirty =
    isEditing && !_.isEqual(draftData[activeTab], savedData[activeTab])

  const handleTabClick = (next: TabKey) => {
    if (next === activeTab) return
    if (isCurrentTabDirty) {
      Modal.confirm({
        title: t('common:confirmation'),
        content: t('monthlyInspection:messages.unsavedChangesConfirm'),
        okText: t('common:btn.confirm'),
        cancelText: t('common:btn.cancel'),
        onOk: () => {
          setDraftData(savedData)
          setActiveTab(next)
        },
      })
      return
    }
    setActiveTab(next)
  }

  const hasEmptyTextAr = (data) => {
    return data.some((subItem) => subItem.textAr === '')
  }
  const handleConfirm = () => {
    const sections = draftData[activeTab]
    for (const sec of sections) {
      if (hasEmptyTextAr(sec.items)) {
        Message.warning(
          t('monthlyInspection:messages.pleaseCompleteRequiredFields'),
        )
        return
      }
    }

    const payload: InspectionSavePayload = {
      type: TAB_KEY_TO_TYPE[activeTab],
      sections: sections.map((sec, index) => ({
        sectionId: sec.sectionId,
        name: sec.titleEn,
        nameAr: sec.titleAr,
        sort: index,
        items: sec.items.map((it, idx) => ({
          itemId: it.itemId,
          name: it.textEn,
          nameAr: it.textAr,
          orgId: it.orgId,
          sort: idx,
        })),
      })),
    }

    runSave(payload)
  }

  // ── Section actions ────────────────────────────────────────────────────
  const handleAddSection = () => {
    const newSection: Section = {
      id: uuidv4(),
      titleAr: '',
      titleEn: '',
      items: [{ id: uuidv4(), textAr: '', textEn: '', orgId: undefined }],
    }
    updateTabSections([...currentSections, newSection])
  }

  const handleDeleteSection = (sectionIdx: number) => {
    updateTabSections(currentSections.filter((_, i) => i !== sectionIdx))
  }

  const handleSectionTitleChange = (sectionIdx: number, value: string) => {
    const updated = currentSections.map((sec, i) => {
      if (i !== sectionIdx) return sec
      return fillInEnglish
        ? { ...sec, titleEn: value }
        : { ...sec, titleAr: value }
    })
    updateTabSections(updated)
  }

  const handleItemOrgChange = (
    sectionIdx: number,
    itemIdx: number,
    value: string | undefined,
  ) => {
    const updated = currentSections.map((sec, i) => {
      if (i !== sectionIdx) return sec
      return {
        ...sec,
        items: sec.items.map((item, j) =>
          j === itemIdx ? { ...item, orgId: value } : item,
        ),
      }
    })
    updateTabSections(updated)
  }

  // ── Item actions ───────────────────────────────────────────────────────
  const handleAddItem = (sectionIdx: number) => {
    const updated = currentSections.map((sec, i) => {
      if (i !== sectionIdx) return sec
      return {
        ...sec,
        items: [...sec.items, { id: uuidv4(), textAr: '', textEn: '' }],
      }
    })
    updateTabSections(updated)
  }

  const handleDeleteItem = (sectionIdx: number, itemIdx: number) => {
    const updated = currentSections.map((sec, i) => {
      if (i !== sectionIdx) return sec
      return { ...sec, items: sec.items.filter((_, j) => j !== itemIdx) }
    })
    updateTabSections(updated)
  }

  const handleItemTextChange = (
    sectionIdx: number,
    itemIdx: number,
    value: string,
  ) => {
    const updated = currentSections.map((sec, i) => {
      if (i !== sectionIdx) return sec
      return {
        ...sec,
        items: sec.items.map((item, j) => {
          if (j !== itemIdx) return item
          return fillInEnglish
            ? { ...item, textEn: value }
            : { ...item, textAr: value }
        }),
      }
    })
    updateTabSections(updated)
  }

  // ── Section drag ───────────────────────────────────────────────────────
  const handleSectionDragStart = (idx: number) => {
    dragSectionIdx.current = idx
  }

  const handleSectionDragOver = (e: React.DragEvent, idx: number) => {
    e.preventDefault()
    dragOverSectionIdx.current = idx
    rerender()
  }

  const handleSectionDrop = () => {
    const from = dragSectionIdx.current
    const to = dragOverSectionIdx.current
    if (from !== null && to !== null && from !== to) {
      const next = [...currentSections]
      const [moved] = next.splice(from, 1)
      next.splice(to, 0, moved)
      updateTabSections(next)
    }
    dragSectionIdx.current = null
    dragOverSectionIdx.current = null
    rerender()
  }

  const handleSectionDragEnd = () => {
    dragSectionIdx.current = null
    dragOverSectionIdx.current = null
    rerender()
  }

  // ── Item drag ──────────────────────────────────────────────────────────
  const handleItemDragStart = (sectionIdx: number, itemIdx: number) => {
    dragItemInfo.current = { sectionIdx, itemIdx }
  }

  const handleItemDragOver = (
    e: React.DragEvent,
    sectionIdx: number,
    itemIdx: number,
  ) => {
    e.preventDefault()
    e.stopPropagation()
    dragOverItemInfo.current = { sectionIdx, itemIdx }
    rerender()
  }

  const handleItemDrop = (e: React.DragEvent, targetSectionIdx: number) => {
    e.stopPropagation()
    const from = dragItemInfo.current
    const to = dragOverItemInfo.current
    if (
      from &&
      to &&
      from.sectionIdx === targetSectionIdx &&
      from.sectionIdx === to.sectionIdx &&
      from.itemIdx !== to.itemIdx
    ) {
      const updated = currentSections.map((sec, i) => {
        if (i !== from.sectionIdx) return sec
        const next = [...sec.items]
        const [moved] = next.splice(from.itemIdx, 1)
        next.splice(to.itemIdx, 0, moved)
        return { ...sec, items: next }
      })
      updateTabSections(updated)
    }
    dragItemInfo.current = null
    dragOverItemInfo.current = null
    rerender()
  }

  const handleItemDragEnd = () => {
    dragItemInfo.current = null
    dragOverItemInfo.current = null
    rerender()
  }

  // ── Render ─────────────────────────────────────────────────────────────
  return (
    <div className={`${classPrefix}`}>
      {/* ── Top bar ── */}
      <div className={`${classPrefix}__topbar`}>
        <div className={`${classPrefix}__title`}>
          {t('monthlyInspection:formSetup.title')}
        </div>

        <div className={`${classPrefix}__topbar-right`}>
          {/* Tabs */}
          <div className={`${classPrefix}__tabs`}>
            {TABS.map((tab) => (
              <button
                key={tab.key}
                className={`${classPrefix}__tab${activeTab === tab.key ? ` ${classPrefix}__tab--active` : ''}`}
                onClick={() => handleTabClick(tab.key)}
              >
                {t(tab.labelKey)}
              </button>
            ))}
          </div>

          {/* Action buttons */}
          {isEditing ? (
            <div className={`${classPrefix}__action-btns`}>
              <Button icon={<IconClose />} onClick={handleCancel}>
                {t('common:btn.cancel')}
              </Button>
              <Button
                type='primary'
                icon={<IconUpload />}
                loading={saveLoading}
                className={`${classPrefix}__confirm-btn`}
                onClick={handleConfirm}
              >
                {t('common:btn.confirm')}
              </Button>
            </div>
          ) : (
            <div className={`${classPrefix}__action-btns`}>
              <Button
                type='primary'
                icon={<IconEdit />}
                className={`${classPrefix}__confirm-btn`}
                onClick={handleEdit}
              >
                {t('monthlyInspection:actions.edit')}
              </Button>
            </div>
          )}
        </div>
      </div>

      <div className={`${classPrefix}__divider`} />

      {/* ── Edit toolbar ── */}
      {isEditing && (
        <div className={`${classPrefix}__edit-toolbar`}>
          <Button type='outline' icon={<IconPlus />} onClick={handleAddSection}>
            {t('monthlyInspection:formSetup.addSection')}
          </Button>
          <div className={`${classPrefix}__fill-en`}>
            <span className={`${classPrefix}__fill-en-label`}>
              {t('monthlyInspection:formSetup.fillInEnglish')}
            </span>
            <Switch
              checked={fillInEnglish}
              onChange={(v) => setFillInEnglish(v)}
              size='small'
            />
          </div>
        </div>
      )}

      {/* ── Floors apply hint (inside / parking) ── */}
      {(activeTab === 'inside' || activeTab === 'parking') && (
        <div className={`${classPrefix}__floors-hint`}>
          <IconInfoCircle className={`${classPrefix}__floors-hint-icon`} />
          <span>
            {activeTab === 'inside'
              ? t('monthlyInspection:formSetup.floorsApplyHint')
              : t('monthlyInspection:formSetup.floorsApplyParking')}
          </span>
        </div>
      )}

      {/* ── Content ── */}
      <Spin loading={sectionsLoading} block className={`${classPrefix}__spin`}>
        {!sectionsLoading &&
          (currentSections.length > 0 ? (
            currentSections.map((section, sectionIdx) => {
              const isDragOverSection =
                isEditing && dragOverSectionIdx.current === sectionIdx

              return (
                <div
                  key={section.id}
                  className={`${classPrefix}__section${isDragOverSection ? ` ${classPrefix}__section--drag-over` : ''}`}
                  draggable={isEditing}
                  onDragStart={() => handleSectionDragStart(sectionIdx)}
                  onDragOver={(e) => handleSectionDragOver(e, sectionIdx)}
                  onDrop={handleSectionDrop}
                  onDragEnd={handleSectionDragEnd}
                >
                  {/* Section header */}
                  <div className={`${classPrefix}__section-header`}>
                    {isEditing && (
                      <span
                        className={`${classPrefix}__drag-handle ${classPrefix}__drag-handle--section`}
                      >
                        <IconDragDot />
                      </span>
                    )}

                    <span className={`${classPrefix}__section-badge`}>
                      {t('monthlyInspection:formSetup.sectionLabel', {
                        n: sectionIdx + 1,
                      })}
                    </span>

                    {isEditing ? (
                      <>
                        <Input
                          className={`${classPrefix}__section-title-input ${fillInEnglish ? '' : 'rtl-input'}`}
                          prefix={
                            fillInEnglish ? (
                              <LangPrefixEn
                                style={{ width: '28px', height: '20px' }}
                              />
                            ) : (
                              <LangPrefixAr
                                style={{ width: '28px', height: '20px' }}
                              />
                            )
                          }
                          value={
                            fillInEnglish ? section.titleEn : section.titleAr
                          }
                          placeholder={t(
                            'monthlyInspection:formSetup.sectionTitlePlaceholder',
                          )}
                          onChange={(v) =>
                            handleSectionTitleChange(sectionIdx, v)
                          }
                          onClick={(e) => e.stopPropagation()}
                          onDragStart={(e) => e.stopPropagation()}
                        />
                        <Button
                          type='outline'
                          size='mini'
                          icon={<IconDelete />}
                          className={`${classPrefix}__delete-btn`}
                          onClick={(e) => {
                            e.stopPropagation()
                            handleDeleteSection(sectionIdx)
                          }}
                        >
                          {t('common:btn.delete')}
                        </Button>
                      </>
                    ) : (
                      <span className={`${classPrefix}__section-title`}>
                        {handelFieldNameShow(section.titleEn, section.titleAr)}
                      </span>
                    )}
                  </div>

                  {/* Items */}
                  {section.items.map((item, itemIdx) => {
                    const isItemDragOver =
                      isEditing &&
                      dragOverItemInfo.current?.sectionIdx === sectionIdx &&
                      dragOverItemInfo.current?.itemIdx === itemIdx

                    return (
                      <div
                        key={item.id}
                        className={`${classPrefix}__item${isItemDragOver ? ` ${classPrefix}__item--drag-over` : ''}`}
                        draggable={isEditing}
                        onDragStart={(e) => {
                          if (!isEditing) return
                          e.stopPropagation()
                          handleItemDragStart(sectionIdx, itemIdx)
                        }}
                        onDragOver={(e) => {
                          if (!isEditing) return
                          handleItemDragOver(e, sectionIdx, itemIdx)
                        }}
                        onDrop={(e) => {
                          if (!isEditing) return
                          handleItemDrop(e, sectionIdx)
                        }}
                        onDragEnd={() => {
                          if (!isEditing) return
                          handleItemDragEnd()
                        }}
                      >
                        {isEditing ? (
                          <>
                            <span className={`${classPrefix}__drag-handle`}>
                              <IconDragDot />
                            </span>
                            <Input
                              className={`${classPrefix}__item-input  ${fillInEnglish ? '' : 'rtl-input'} `}
                              prefix={
                                fillInEnglish ? (
                                  <LangPrefixEn
                                    style={{ width: '28px', height: '20px' }}
                                  />
                                ) : (
                                  <LangPrefixAr
                                    style={{ width: '28px', height: '20px' }}
                                  />
                                )
                              }
                              value={fillInEnglish ? item.textEn : item.textAr}
                              placeholder={t(
                                'monthlyInspection:formSetup.itemPlaceholder',
                              )}
                              onChange={(v) =>
                                handleItemTextChange(sectionIdx, itemIdx, v)
                              }
                              onClick={(e) => e.stopPropagation()}
                              onDragStart={(e) => e.stopPropagation()}
                            />
                            <span className={`${classPrefix}__item-dept-label`}>
                              {t('monthlyInspection:formSetup.responsibleDept')}
                              :
                            </span>
                            <TreeSelect
                              className={`${classPrefix}__item-dept-select`}
                              value={item.orgId}
                              treeData={orgData}
                              placeholder={t('common:pleaseSelect')}
                              allowClear
                              onChange={(v: string | undefined) =>
                                handleItemOrgChange(
                                  sectionIdx,
                                  itemIdx,
                                  v != null && v !== '' ? v : undefined,
                                )
                              }
                              onClick={(e: React.MouseEvent) =>
                                e.stopPropagation()
                              }
                            />
                            <Button
                              type='text'
                              size='mini'
                              icon={<IconCloseCircleFill />}
                              className={`${classPrefix}__item-remove`}
                              onClick={(e) => {
                                e.stopPropagation()
                                handleDeleteItem(sectionIdx, itemIdx)
                              }}
                            />
                          </>
                        ) : (
                          <>
                            <span className={`${classPrefix}__item-text`}>
                              {handelFieldNameShow(item.textEn, item.textAr)}
                            </span>
                            <div className={`${classPrefix}__item-dept`}>
                              <span
                                className={`${classPrefix}__item-dept-label`}
                              >
                                {t(
                                  'monthlyInspection:formSetup.responsibleDept',
                                )}
                                :
                              </span>
                              <span
                                className={`${classPrefix}__item-dept-value`}
                              >
                                {findOrgTitleByKey(orgData, item.orgId)}
                              </span>
                            </div>
                          </>
                        )}
                      </div>
                    )
                  })}

                  {/* Add item row */}
                  {isEditing && (
                    <div className={`${classPrefix}__add-item`}>
                      <Button
                        type='text'
                        size='mini'
                        icon={<IconPlus />}
                        className={`${classPrefix}__add-item-btn`}
                        onClick={(e) => {
                          e.stopPropagation()
                          handleAddItem(sectionIdx)
                        }}
                      >
                        {t('monthlyInspection:formSetup.addItem')}
                      </Button>
                    </div>
                  )}
                </div>
              )
            })
          ) : (
            <div className={`${classPrefix}__content`}>
              <div className={`${classPrefix}__empty`}>
                <div className={`${classPrefix}__empty-text`}>
                  {t('monthlyInspection:formSetup.noSections')}
                </div>
                <Button
                  type='primary'
                  icon={<IconPlus />}
                  className={`${classPrefix}__empty-add-btn`}
                  onClick={() => {
                    if (!isEditing) handleEdit()
                    handleAddSection()
                  }}
                >
                  {t('monthlyInspection:formSetup.addSection')}
                </Button>
              </div>
            </div>
          ))}
      </Spin>
    </div>
  )
}

export default InspectionFormSetup

