  &__add-item-btn {
    color: #30647f;
    padding-left: 0;
    font-size: 14px;
    font-weight: 400;
  }

  // ── Drag handle ───────────────────────────────────────────────────────────
  &__drag-handle {
    display: inline-flex;
    align-items: center;
    justify-content: center;
    color: #4e5969;
    cursor: grab;
    flex-shrink: 0;
    font-size: 16px;
    padding: 2px;
    border-radius: 3px;
    transform: rotate(90deg);
    // border: 1px solid red;

    &:hover {
      color: #86909c;
    }

    &:active {
      cursor: grabbing;
    }

    &--section {
      font-size: 18px;
      transform: rotate(90deg);
    }
  }

  // ── Delete button ─────────────────────────────────────────────────────────
  &__delete-btn {
    flex-shrink: 0;
    margin-left: auto;
    width: 85px;
    height: 29px;
    background-color: #ffffff;
    border: 1px solid red;
    width: 85px;
    height: 29px;
    background-color: #ffffff;
  }

  // ── Floors apply hint ─────────────────────────────────────────────────────
  &__floors-hint {
    display: flex;
    align-items: center;
    gap: 8px;
    padding: 12px 16px;
    margin-bottom: 24px;
    background: #e0efff;
    border-radius: 8px;
    color: #186ac2;
    font-size: 13px;

    &-icon {
      font-size: 16px;
    }
  }
}

.patrol-form-setup {
  box-sizing: border-box;
  margin-top: 16px;
  width: 100%;
  background-color: #fff;
  border-radius: 12px;
  box-shadow: 0px 4px 8px rgba(0, 0, 0, 0.05);
  padding: 24px;
  // height: 88vh;
  height: calc(100vh - 80px);

  // ── Top bar ──────────────────────────────────────────────────────────────
  &__topbar {
    display: flex;
    flex-direction: column;
    font-size: 24px;
    font-weight: 500;
    margin-bottom: 16px;
    gap: 16px;
    flex-wrap: wrap;
    border: 1px solid rgb(240, 240, 240);
    padding: 16px;
    border-radius: 10px;
    box-shadow: 0px 0px 12.6px 0px rgba(0, 0, 0, 0.07);

    box-shadow: 0px 9px 11.5px 0px rgba(0, 0, 0, 0.04);
  }

  &__title {
    color: #000;
    font-size: 24px;
    font-weight: 500;
    text-transform: uppercase;
    flex-shrink: 0;
  }

  &__topbar-right {
    display: flex;
    align-items: center;
    gap: 16px;
    flex: 1;
    justify-content: space-between;
  }

  // ── Tabs ──────────────────────────────────────────────────────────────────
  &__tabs {
    display: flex;
    flex-direction: row;
    gap: 8px;
    flex-shrink: 0;
  }

  &__tab {
    display: inline-flex;
    align-items: center;
    justify-content: center;
    padding: 6px 16px;
    border-radius: 6px;
    border: 1px solid #c9cdd4;
    background: #fff;
    color: #1d2129;
    font-size: 14px;
    cursor: pointer;
    white-space: nowrap;
    transition:
      border-color 0.2s,
      color 0.2s,
      background 0.2s;

    &:hover {
      border: 1px solid #30647f;
      color: #30647f;
    }

    &--active {
      border: 1px solid #30647f;
      color: #30647f;
      background-color: #f7f8fa;
      font-weight: 500;
    }
  }

  // ── Action buttons ────────────────────────────────────────────────────────
  &__action-btns {
    display: flex;
    align-items: center;
    gap: 8px;
    flex-shrink: 0;
  }

  // ── Divider ───────────────────────────────────────────────────────────────
  &__divider {
    height: 1px;
    background-color: #e5e6eb;
    margin-bottom: 20px;
  }

  // ── Edit toolbar ──────────────────────────────────────────────────────────
  &__edit-toolbar {
    display: flex;
    align-items: center;
    justify-content: space-between;
    margin-bottom: 16px;
  }

  &__fill-en {
    display: flex;
    align-items: center;
    gap: 8px;
  }

  &__fill-en-label {
    font-size: 14px;
    font-weight: 400;
    color: #30647f;
  }

  // ── Content area ──────────────────────────────────────────────────────────
  &__content {
    display: flex;
    flex-direction: column;
    gap: 0;
    border: 1px solid #e5e6eb;
    border-radius: 8px;
    overflow: hidden;
  }

  &__spin {
    // display: block;
    width: 100%;
    // min-height: 240px;
    border-radius: 8px;
    border: 1px solid #e5e6eb;

    &.arco-spin-loading {
      display: flex;
      align-items: center;
      justify-content: center;
    }
  }

  &__empty {
    padding: 40px;
    text-align: center;
    color: #86909c;
    font-size: 14px;
    display: flex;
    flex-direction: column;
    align-items: center;
    gap: 16px;
  }

  // ── Section ───────────────────────────────────────────────────────────────
  &__section {
    border-bottom: 1px solid #e5e6eb;

    &:last-child {
      border-bottom: none;
    }

    &--drag-over {
      outline: 2px dashed #196d65;
      outline-offset: -2px;
      background-color: rgba(25, 109, 101, 0.04);
    }
  }

  &__section-header {
    display: flex;
    align-items: center;
    gap: 20px;
    padding: 8px 16px;
    background-color: #f7f8fa;
    border-bottom: 1px solid #e5e6eb;
  }

  // 第一个 section 的表头顶部圆角
  &__section:first-child &__section-header {
    border-top-left-radius: 8px;
    border-top-right-radius: 8px;
  }

  &__section-badge {
    display: inline-flex;
    align-items: center;
    justify-content: center;
    padding: 2px 10px;
    border-radius: 4px;
    background-color: #e5e6eb;
    color: #30647f;
    font-size: 12px;
    font-weight: 500;
    white-space: nowrap;
    flex-shrink: 0;
  }

  &__section-title {
    font-size: 15px;
    font-weight: 500;
    color: #1d2129;
    flex: 1;
  }

  &__section-title-input {
    flex: 1;

    .arco-input-inner-wrapper {
      background-color: #fff;
    }

    .arco-input-prefix {
      padding-right: 6px;
      display: inline-flex;
      align-items: center;
    }
    &.rtl-input {
      .arco-input {
        padding-right: 12px;
      }
    }
  }

  // ── Item ──────────────────────────────────────────────────────────────────
  &__item {
    display: flex;
    align-items: center;
    gap: 10px;
    padding: 0px 12px 0px 12px;
    min-height: 48px;
    background-color: #fff;
    transition: background-color 0.15s;
    justify-content: space-between;
    border-bottom: 1px solid #e5e6eb;

    &:last-child {
      border-bottom: none;
    }

    &--drag-over {
      outline: 2px dashed #196d65;
      outline-offset: -2px;
      background-color: rgba(25, 109, 101, 0.04);
    }
  }

  // 最后一个 section 的最后一个 item 底部圆角
  &__section:last-child &__item:last-child {
    border-bottom-left-radius: 8px;
    border-bottom-right-radius: 8px;
  }

  .edit-table-item {
    padding: 0px 12px 0px 60px;
    width: 100%;
    display: flex;
    justify-content: space-between;
    gap: 14px;
    align-items: center;
  }

  .table-item {
    width: 100%;
    display: flex;
  }

  &__item-text {
    font-size: 14px;
    color: #1d2129;
  }

  &__item-input {
    flex: 1;

    .arco-input-inner-wrapper {
      background-color: #fff;
    }

    .arco-input-prefix {
      padding-right: 6px;
      display: inline-flex;
      align-items: center;
    }
    &.rtl-input {
      .arco-input {
        padding-right: 12px;
      }
    }
  }

  &__item-remove {
    flex-shrink: 0;
    color: #86909c !important;
    width: 20px;
    height: 20px;
  }

  // ── Item dept ─────────────────────────────────────────────────────────────
  &__item-dept {
    display: flex;
    align-items: center;
    gap: 6px;
    margin-left: auto;
    flex-shrink: 0;
  }

  &__item-dept-label {
    font-size: 13px;
    color: #86909c;
    white-space: nowrap;
    flex-shrink: 0;
  }

  &__item-dept-value {
    font-size: 13px;
    color: #1d2129;
    font-weight: 500;
  }

  &__item-dept-select {
    width: 200px;
    flex-shrink: 0;

    .arco-select-view {
      background-color: #fff;
    }
  }

  // ── Add item row ──────────────────────────────────────────────────────────
  &__add-item {
    padding: 8px 16px 8px 48px;
    background-color: #fff;
  }

  &__add-item-btn {
    color: #30647f;
    padding-left: 0;
    font-size: 14px;
    font-weight: 400;
  }

  // ── Drag handle ───────────────────────────────────────────────────────────
  &__drag-handle {
    display: inline-flex;
    align-items: center;
    justify-content: center;
    color: #c9cdd4;
    cursor: grab;
    flex-shrink: 0;
    font-size: 16px;
    padding: 2px;
    border-radius: 3px;
    transform: rotate(90deg);

    &:hover {
      color: #86909c;
    }

    &:active {
      cursor: grabbing;
    }

    &--section {
      font-size: 18px;
      transform: rotate(90deg);
    }
  }

  // ── Delete button ─────────────────────────────────────────────────────────
  &__delete-btn {
    flex-shrink: 0;
    margin-left: auto;
    width: 85px;
    height: 29px;
    background-color: #ffffff;
  }

  // ── Floors apply hint ─────────────────────────────────────────────────────
  &__floors-hint {
    display: flex;
    align-items: center;
    gap: 8px;
    padding: 12px 16px;
    margin-bottom: 24px;
    background: #e0efff;
    border-radius: 8px;
    color: #186ac2;
    font-size: 13px;

    &-icon {
      font-size: 16px;
    }
  }
}

