  &__head-text {
    display: flex;
    flex-direction: column;
    gap: 2px;
  }
  &__category {
    color: #30647f;
    font-size: 12px;
    font-weight: 500;
    line-height: 22px;
    text-transform: uppercase;
    letter-spacing: 0.5px;
  }
  &__title {
    color: #1d2129;
    font-size: 20px;
    font-weight: 500;
    line-height: 28px;
    text-transform: uppercase;
    letter-spacing: 1px;
  }

  &__body {
    padding: 0 20px;
  }
  &__item {
    padding: 20px 0;
    border-bottom: 1px solid #e5e6eb;
    &--last {
      border-bottom: none;
    }
  }

  /* question row: question text left, single pill right */
  &__question {
    display: flex;
    flex-direction: column;
    gap: 16px;
