  &__finding-title {
    font-size: 14px;
    font-weight: 500;
    color: #1d2129;
    text-transform: uppercase;
    letter-spacing: 0.5px;
  }
  &__finding-row {
    display: grid;
    grid-template-columns: 1fr 1fr;
    gap: 16px;
