  overflow: hidden;

  &__header {
    display: flex;
    align-items: center;
    justify-content: space-between;
    height: 72px;
    padding: 12px 20px;
    background: #f7f8fa;
    border-bottom: 1px solid #e5e6eb;
    cursor: pointer;
    user-select: none;
    color: #86909c;
  }
  &__head-text {
    display: flex;
    flex-direction: column;
    gap: 2px;
  }
  &__category {
    color: #30647f;
    font-size: 12px;
    font-weight: 500;
    line-height: 22px;
    text-transform: uppercase;
    letter-spacing: 0.5px;
  }
  &__title {
    color: #1d2129;
    font-size: 20px;
    font-weight: 500;
    line-height: 28px;
    text-transform: uppercase;
    letter-spacing: 1px;
  }

  &__body {
    padding: 0 20px;
  }
  &__item {
    padding: 20px 0;
    border-bottom: 1px solid #e5e6eb;
    &--last {
      border-bottom: none;
    }
  }

  /* question row: question text left, single pill right */
  &__question {
    display: flex;
    flex-direction: column;
    gap: 16px;
  }
  &__question-row {
    display: flex;
    align-items: center;
    justify-content: space-between;
    gap: 16px;
  }
  &__question-text {
    flex: 1;
    min-width: 0;
    font-size: 16px;
    font-weight: 500;
    line-height: 22px;
    color: #1d2129;
  }

  /* single answer pill (yes = brand gradient, no = red gradient) */
  &__pill {
    flex-shrink: 0;
    display: inline-flex;
    align-items: center;
    justify-content: center;
    min-width: 40px;
    height: 36px;
    padding: 0 24px;
    border-radius: 6px;
    color: #ffffff;
    font-size: 14px;
    font-weight: 500;
    line-height: 22px;
    user-select: none;

    &--yes {
      background: linear-gradient(to top, #30647f, #4a8099);
      box-shadow: 0 2px 6px rgba(48, 100, 127, 0.25);
    }
    &--no {
      background: linear-gradient(to top, #cb3d4b, #f5626c);
      box-shadow: 0 2px 6px rgba(203, 61, 75, 0.25);
    }
  }

  /* shared gray container for findings (NO nested white finding cards) */
  &__findings {
    background: #f7f8fa;
    border-radius: 8px;
    padding: 0 20px 20px 20px;
  }
  &__finding {
    display: flex;
    flex-direction: column;
    // gap: 12px;
    padding: 14px 0px;
    background: repeating-linear-gradient(
      to right,
      #dcdce1,
      #dcdce1 4px,
      transparent 4px,
      transparent 9px
    );
    background-repeat: repeat-x;
    background-position: bottom;
    background-size: 100% 1px;
    &--has-divider {
      // margin-top: 20px;
      padding-top: 10px;
    }
  }
  &__finding-title {
    font-size: 14px;
    font-weight: 500;
    color: #1d2129;
    text-transform: uppercase;
    letter-spacing: 0.5px;
  }
  &__finding-row {
    display: grid;
    grid-template-columns: 1fr 1fr;
    gap: 16px;
  }

  &__field {
    display: flex;
    flex-direction: column;
    gap: 4px;
  }
  &__field-label {
    font-size: 12px;
    line-height: 22px;
    color: #86909c;
  }
  &__field-value {
    font-size: 14px;
    line-height: 22px;
    color: #1d2129;
    min-height: 22px;
    white-space: pre-wrap;
    word-break: break-word;
  }
}
